var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"문이 잠겨 있네요.","JPN":"ドアにカギがかかっていますね。","ENG":"The door seems to be locked.","TWN":"門鎖起來了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"잠시 기다리세요. 열쇠를 가져오겠습니다.","JPN":"少々お待ちください。カギをお持ちします。","ENG":"Hold on. I'll go get the keys.","TWN":"請稍候，我去拿鑰匙。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 시니어님……?","JPN":"し、シニア……？","ENG":"S-sir...?","TWN":"Senior……？"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L6_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"머리가…… 사라졌어? 이, 이게 대체 무슨……?","JPN":"頭部が……消えている？　こ、これはいったいどういう……？","ENG":"Where's... his head? W-what's happened to him...?","TWN":"頭……不見了？怎，怎麼會這樣……？"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님, 이건…….","JPN":"社長、これって……","ENG":"Boss, this looks like...","TWN":"老闆，這是……"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원들에게 연락해 주게나, 미나 양.","JPN":"社員たちに連絡してくれ、ミナ君。","ENG":"Mina, go call our employees.","TWN":"米娜，幫我聯絡大家。"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 좀 바빠질 것 같군.","JPN":"どうやら忙しくなりそうだ。","ENG":"It looks like we'll be busy soon.","TWN":"看來之後會有點忙。"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 시간 뒤","JPN":"1時間後","ENG":"1 hour later","TWN":"一小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 대장님.","JPN":"はい、隊長。","ENG":"Yes, Commander.","TWN":"你好，隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당연히 안 받을 줄 알았는데, 의외의 반응이네요.","JPN":"絶対に出ないと思ってたのに、意外ですね。","ENG":"I didn't think you'd pick up. This is unexpected.","TWN":"我還以為你肯定不會接呢，真出乎意料。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뻔뻔하게 전화를 거셨으니, 저도 뻔뻔하게 받은 것뿐인 걸요.","JPN":"図々しく電話をかけてきましたので、私も図々しく出ただけです。","ENG":"Well, you were shameless enough to call, so I am being shameless and picking up.","TWN":"你厚著臉皮打了電話，我就厚著臉皮接了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저와 무슨 대화가 하고 싶은 거죠?","JPN":"なにか私に用件ですか？","ENG":"What did you want to talk about?","TWN":"你想和我談什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아주 요란스럽게 일을 벌이고 떠났더군요.","JPN":"また盛大にやってくれましたね。","ENG":"You really stirred things up before you left.","TWN":"我看你惹出了不少麻煩呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어를 그런 식으로 처리할 줄은 몰랐어요.","JPN":"シャレードのシニアをあんなふうに処理するとは思いませんでした。","ENG":"I never expected you to take care of Charade's Senior in that manner.","TWN":"沒想到會以那種方式處理查雷德的Senior。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 누군가 제 뒤를 캐는 걸 별로 좋아하지 않거든요.","JPN":"私は誰かに調査されるのが、好きではありませんので。","ENG":"I'm not a fan of people prying on me.","TWN":"因為我不喜歡有人在背後摸我底細。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 따르는 그 새침데기 리트리버도 마찬가지고요.","JPN":"あなたに従うあのすましたレトリーバーもそうです。","ENG":"Including that coy little retriever of yours.","TWN":"你那隻裝模作樣的獵犬也一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제법 감정적이시네요. 저희가 스완 씨의 심기를 제대로 거슬렀나 봐요.","JPN":"思ったより感情的なんですね。僕たちがスワンさんの機嫌を損ねてしまったようです。","ENG":"You're quite emotional. We must've upset you deeply.","TWN":"你似乎很激動，我們是不是惹你生氣了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 예정된 전개예요. 제 감정은 한 번도 각본을 벗어난 적이 없습니다.","JPN":"すべて予想された展開でした。私の感情は一度も脚本から外れたことはありません。","ENG":"Everything is according to plan. My emotions have never strayed from the script.","TWN":"一切都是事先安排好的。我的情緒從來沒有脫離過劇本。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만, 그 대답을 듣고도 잘 이해가 안 되는 부분이 있어요.","JPN":"そうでしょうか？　でも、気になるところがあります。","ENG":"But that answer is still not enough to help me understand this one thing.","TWN":"不過，我對這個答案還是有些不太理解。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 분명 그날 최고관리자님의 정체를 알아봤을 텐데요.","JPN":"あなたは確かにあの日、最高管理者さんの正体を知ったはずです。","ENG":"I'm sure you recognized the Supreme Administrator's identity that day.","TWN":"你那天一定認出了最高管理者的真實身分。"},"stage":{"bg":"STADIUM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리자님을 노리는 건, 보안을 뚫고 그 시니어를 처리하는 것보다 쉬운 일이었겠죠. 그렇지 않나요?","JPN":"管理者さんを狙うのは、保安を突破してあのシニアを処理することより簡単だった。違いますか？","ENG":"Going for the Administrator would've been easier than going through all that security to eliminate the Senior, am I wrong?","TWN":"與其突破保全處理Senior，直接對管理者下手應該更容易不是嗎？"},"stage":{"bg":"STADIUM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗, 모든 걸 알고 있는 양 말하던 당신도… 지금은 호기심 많은 아이일 뿐이군요.","JPN":"ふふっ、すべてを知っているかのように話していたあなたも……今では好奇心旺盛な子ども同然ですね。","ENG":"Fu fuu, you used to act like you knew everything... and now you're just another child, full of curiosity.","TWN":"呵呵，你雖然一副什麼都知道的語氣……但其實你也是一個充滿好奇心的孩子而已。"},"stage":{"bg":"STADIUM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하지 않았다. 그 정도 설명으론 부족할까요?","JPN":"私がそれを望んでいなかった。この説明で納得していただけるでしょうか？","ENG":"I didn't want to. Is that enough of a reason for you?","TWN":"我並不想這麼做。這個理由充分嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 그토록 찾았고, 당신의 각본에 걸림돌이 될 게 뻔한 존재일 텐데요?","JPN":"あなたがあんなにも探し求め、恐らくあなたの脚本の邪魔になる存在なのにですか？","ENG":"You were looking for him so hard, and he's sure to be an obstacle in your play.","TWN":"那是你一直在追尋的，會成為你的劇本當中的絆腳石的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"ええ。","ENG":"It's fine.","TWN":"無所謂。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 오히려 그 사람이 살아서 봐줬으면 하거든요.","JPN":"私はむしろ、あの人に生きて見届けてもらいたいのです。","ENG":"I'd prefer him to survive and watch.","TWN":"我寧願他活著看到這一切。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 곧 이뤄내게 될 일들을.","JPN":"もうすぐ私が成し遂げることを。","ENG":"Watch the things I'm about to accomplish.","TWN":"看到我將實現的一切目標。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"대장, 아까부터 뭘 그렇게 골몰히 생각하시죠?","JPN":"隊長、先程から何をそんなに考え込んでいるのですか？","ENG":"Commander, you've been deep in thought for a while now.","TWN":"隊長，您從剛剛開始就在想什麼呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"역시 그 여자에 관한 건가요?","JPN":"やはりあの女のことですか。","ENG":"Is it about that woman, again?","TWN":"果然是在想那個女人的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 아무래도 위화감이 느껴져서요.","JPN":"はい、どうしても違和感があって。","ENG":"Yes. I can't shake this sense of unease.","TWN":"嗯，總覺得有種違和感。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"위화감이라면……?","JPN":"違和感……？","ENG":"Sense of unease...?","TWN":"違和感……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스완의 모든 행동은 마치 잘 만들어진 한 편의 연극을 보는 느낌이에요.","JPN":"これまでスワンが見せてきた一連の行動は、まるでよくできた演劇を観ているかのようです。","ENG":"Everything Swan does feels like watching a meticulously crafted play.","TWN":"史旺的一舉一動，都像是一齣精心編排的話劇。"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"무대 위에 있는 등장인물들은 알 도리가 없지만.","JPN":"舞台の上にいる登場人物には知る術がありませんが……","ENG":"The actors on the stage have no way of knowing.","TWN":"雖然舞台上的演員無從得知，"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"무대 너머 객석에 앉은 관객들은, 어느 시점에서 캐치할 수 있는 감각이랄까……?","JPN":"舞台の向こう、客席に座る観客にならある時点から気が付くことができる感覚といいますか……","ENG":"But the audience eventually senses it at some point...","TWN":"但坐在舞台另一側觀眾席的人，卻會在某個瞬間察覺的那種感覺……？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"연극이라…….","JPN":"演劇……","ENG":"A play...","TWN":"話劇啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"본 적이 없어서 잘은 모르겠지만, 역시 그 여자가 남을 속이는 배우이기 때문이겠죠.","JPN":"観たことがないので詳しくはありませんが、それはやはりあの女が人を騙す役者だからでしょう。","ENG":"I have never seen one myself, but perhaps that is simply because she is an actress who deceives others.","TWN":"雖然我沒看過不太清楚，不過那是因為她是個擅長欺騙他人的演員吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"배우라고요?","JPN":"役者？","ENG":"Actress?","TWN":"演員？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"이 <color=#ffd34c>눈</color>으로 꿰뚫어본 그녀의 과거는…….","JPN":"この<color=#ffd34c>目</color>で見たあの女の過去は……","ENG":"Her past I pierced through with my <color=#ffd34c>eye</color>...","TWN":"我用這雙<color=#ffd34c>眼睛</color>看透她的過去……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"자신의 세계를 짓밟았던 타기리온과 계약을 맺은 뒤.","JPN":"自分の世界を踏みにじったタギリオンと契約を結び……","ENG":"After forming a contract with Thagirion, the one who trampled her world.","TWN":"在與踐踏了自己世界的塔基里翁締結契約後，"},"stage":{"bg":"SWANSONG_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"자기 세계를 되돌리기 위해, 똑같이 다른 세계를 짓밟고 다니는 광경이었어요.","JPN":"自分の世界を元に戻すために、同じように他の世界を踏みにじる光景でした。","ENG":"She went on to trample other worlds in the same way, all to reclaim her own.","TWN":"為了奪回自己的世界，反過來踐踏其他世界的情景。"},"stage":{"bg":"SWANSONG_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"심야의 살인마로서… 때로는 전쟁으로, 때로는 선동으로…….","JPN":"深夜の殺人鬼として……時には戦争で、時には扇動で……","ENG":"As the Midnight Killer, sometimes through war, sometimes through incitement...","TWN":"身為午夜殺人魔……有時是戰爭，有時是煽動……"},"stage":{"bg":"SWANSONG_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"수없이 자기 모습을 바꿔가며, 많은 이들을 속이고 기만하던 런던의 프리마돈나…….","JPN":"絶えず己の姿を変えながら、大勢の者を騙したロンドンのプリマドンナ……","ENG":"Changing her face countless times, deceiving and manipulating many people, the prima donna of London.","TWN":"不斷改變自身姿態，欺騙、愚弄無數人的倫敦首席女伶……"},"stage":{"bg":"SWANSONG_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그것이 제가 꿰뚫어 본 스완의 실체였으니까요.","JPN":"それが私が見たスワンの実体でした。","ENG":"That's the true nature of Swan I saw.","TWN":"那就是我看穿的史旺真面目。"},"stage":{"bg":"SWANSONG_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"결국, 그 여자에게 있어서 이번 세계도 똑같을 겁니다.","JPN":"結局、あの女にとってはこの世界も同じなのでしょう。","ENG":"In the end, this world will be no different to her.","TWN":"最終對她而言，這個世界也一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"자신의 목적을 이룰 가망이 없다고 판단하면, 가차 없이 잘라버릴 테니까요.","JPN":"目的を叶えられる希望がないと判断したら、容赦なく切り捨てるはずです。","ENG":"The moment she judges her goal to be unattainable, she will discard it without hesitation.","TWN":"一旦她判斷無法達成目的，就會毫不留情割捨一切。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론, 그럴 가능성이 높겠죠.","JPN":"もちろん、その可能性は高いでしょう。","ENG":"Yes, that's highly likely.","TWN":"確實很有可能如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 어째선지 저는 스완이 뭔가를 감추고 있다는 생각을 지울 수가 없어서요.","JPN":"ですが、僕はなぜかスワンが何かを隠している気がしてならないんです。","ENG":"But for some reason, I can't shake the feeling that Swan is hiding something.","TWN":"但不知為何，我始終覺得史旺隱瞞了某些事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"뭔가를 감춘다고요……?","JPN":"何かを隠している……？","ENG":"Hiding something...?","TWN":"隱瞞某些事……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"훌륭한 배우는 배역에 몰입하기 위해, 자기 자신마저 속인다고 하죠.","JPN":"立派な役者は役に没頭するために自分自身をも騙すと言います。","ENG":"A great actor deceives even themselves in order to fully immerse in a role.","TWN":"優秀的演員為了投入角色，甚至會欺騙自己。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 감춘다는 건, 언젠가 그것이 드러나기를 바라는 반발 심리이기도 해요.","JPN":"ですが隠すという行為には、いつかそれが暴かれることを望む反対の心理があったりするんです。","ENG":"But to hide something also reflects a subconscious desire for it to be revealed someday.","TWN":"但隱瞞同時也是一種希望某天被揭露的反抗心理。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한 가지만 물어봐도 괜찮을까요, 지수 씨?","JPN":"1つだけ聞いてもいいでしょうか？　シノさん。","ENG":"May I ask you one thing, Jisoo?","TWN":"可以問你一個問題嗎，智秀？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"만약, 지수 씨에게 들키고 싶지 않은 부끄러운 물건이 있다면…….","JPN":"もし、シノさんが人に知られたくない恥ずかしい物を持っていたとしたら……","ENG":"If you had something shameful that you didn't want me to discover...","TWN":"如果有一樣不想被發現的害羞物品……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지수 씨는 그걸 어디에 숨길 건가요?","JPN":"シノさんはそれをどこに隠しますか？","ENG":"Where would you hide it?","TWN":"你會把它藏在哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"부, 부끄러운 물건이라고요? 갑자기 그런 걸 왜……!?","JPN":"は、恥ずかしい物？　なぜ急にそんなことを……！？","ENG":"S-something shameful? Why bring that up all of a sudden...?!","TWN":"害、害羞的物品！？為什麼會突然問這個……！？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어디까지나 가정이에요.","JPN":"まあ、もしもの話ですから。","ENG":"It's purely hypothetical.","TWN":"這只是個假設而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"크, 크흠…! 저라면…….","JPN":"ご、ごほん……！　私なら……","ENG":"A-ahem...! If it were me...","TWN":"咳、咳嗯……！如果是我的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"<color=#ffd34c>아무도 오지 않는 곳</color>에 묻어버릴 것 같군요.","JPN":"<color=#ffd34c>誰も来ない場所</color>に埋めてしまう、ではないかと。","ENG":"I would bury it in a place <color=#ffd34c>no one ever comes to</color>.","TWN":"我會把它埋在<color=#ffd34c>沒有人會來的地方</color>吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그것이 묻혀 있다는 사실을, 아는 사람이 저밖에 없는 곳.","JPN":"そこにそれが埋まっていることを、自分しか知らない場所に。","ENG":"A place where I am the only one who knows it is buried there.","TWN":"只有我一個人知道它被埋在那裡的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아무도 오지 않는 곳이라…….","JPN":"誰も来ない場所か……","ENG":"A place no one ever comes to...","TWN":"沒有人會來的地方啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라? 그 말은 지수 씨의 부끄러운 물건이 어딘가 파묻혀 있다는 뜻일까요?","JPN":"あれ？　ということは、シノさんの恥ずかしい物はどこかに埋まっているということですか？","ENG":"Oh? Does that mean your shameful item is buried somewhere, Jisoo?","TWN":"咦？那不就表示智秀小姐有埋著什麼害羞的東西嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"대, 대장……!","JPN":"た、隊長……！","ENG":"C-Commander...!","TWN":"隊、隊長……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 농담이에요.","JPN":"はは、冗談です。","ENG":"Haha, just joking.","TWN":"哈哈，我開玩笑的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 참고가 되었어요. 고마워요.","JPN":"でも参考になりました。ありがとうございます。","ENG":"But that was helpful. Thank you.","TWN":"不過很有參考價值，謝謝你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"참고라니, 무슨 참고가…….","JPN":"参考って、何の参考に……","ENG":"Helpful? Helpful in what way...?","TWN":"參考是參考什麼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 방금 이야기도 에이미 양에게는 비밀로 해주세요.","JPN":"それと、今の話もエイミーさんには秘密にしてください。","ENG":"And please keep what we just discussed a secret from Amy as well.","TWN":"還有，剛剛的對話請對艾米保密。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그녀의 세계를 멸망시킨 배후가 스완이라는 걸, 그녀가 알게 되면…….","JPN":"自分の世界を滅ぼした黒幕が、実はスワンであることを彼女が知ってしまったら……","ENG":"If she were to learn that Swan was behind the destruction of her world...","TWN":"要是她知道摧毀她世界的幕後黑手是史旺……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이래저래 일을 그르칠 가능성이 생기거든요.","JPN":"色々とややこしくなる可能性があるので。","ENG":"There would be too many ways for things to go wrong.","TWN":"事情恐怕會變得很麻煩。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 결국 드러나기야 하겠지만, 그 시점은 마지막까지 미뤄두는 편이 좋을 거예요.","JPN":"結局はバレるでしょうが、その時が来るのは最後の最後になった方がいいでしょうから。","ENG":"Well, it'll all come to light eventually, but it's better to delay that moment as long as possible.","TWN":"雖然最後終究會曝光，但時機越晚越好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 말, 무슨 뜻인지 알겠죠?","JPN":"僕の言ってること、わかりますね？","ENG":"You understand what I mean, right?","TWN":"你明白我的意思吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"명심하겠습니다. 대장.","JPN":"肝に銘じます、隊長。","ENG":"I will keep it firmly in mind, Commander.","TWN":"我會銘記在心的，隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};